def _run_hook_with_payload(hook_path, payload):
    """Run a hook script with a JSON payload on stdin; return (exit, stdout, stderr)."""
    proc = subprocess.run(
        ["bash", str(hook_path)],
        input=json.dumps(payload),
        capture_output=True,
        text=True,
        timeout=10,
    )
    return proc.returncode, proc.stdout, proc.stderr


