def test_AC_04_g_script_evidence():
    """Validate the g.script evidence artifact captured by the main-agent
    orchestrator (per AC-04 spec, QA does NOT run g.script itself — main
    agent runs it and writes evidence to
    .claude/dev-registry/dev-20260524-205206/g-script-evidence.json).
    If the artifact is missing this test is skipped (QA Phase: orchestrator
    has not yet run the g.script harness)."""
    evidence_path = REPO_ROOT / ".claude" / "dev-registry" / "dev-20260524-205206" / "g-script-evidence.json"
    if not evidence_path.exists():
        pytest.skip(f"g.script evidence artifact not yet produced at {evidence_path}")
    data = json.loads(evidence_path.read_text(encoding="utf-8"))
    for case in ("g_script_1", "g_script_2", "g_script_3"):
        assert case in data, f"evidence missing case {case}"
    # g_script_1: auth-absent → non-zero exit + stderr contains the literal message + flag never existed pre and absent post
    g1 = data["g_script_1"]
    assert g1["exit_code"] != 0
    assert "BULK mode requires explicit user authorization" in g1.get("stderr", "")
    # g_script_2: auth-present + write succeeds → zero exit + flag unlinked post
    g2 = data["g_script_2"]
    assert g2["exit_code"] == 0
    assert g2.get("flag_existed_pre") is True
    assert g2.get("flag_existed_post") is False
    # g_script_3: auth-present + write fails → non-zero exit + flag STILL unlinked post (unlink-first verification)
    g3 = data["g_script_3"]
    assert g3["exit_code"] != 0
    assert g3.get("flag_existed_pre") is True
    assert g3.get("flag_existed_post") is False


